const data = $json;

const brl = new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL'
});

function clean(text) {
  return String(text || '')
    .replace(/[<>{}`*_#\[\]\(\)]/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function fmtDate(value) {
  if (!value) return 'sem data';
  return new Date(value).toLocaleDateString('pt-BR');
}

function formatMeios(meios) {
  if (!meios || meios.length === 0) return 'Sem dados';

  return meios.map(item =>
    `• ${clean(item.DESCRICAO)}: ${brl.format(Number(item.VALOR || 0))}`
  ).join('\n');
}

function formatTop(top) {
  if (!top || top.length === 0) return 'Sem dados';

  return top.map((item, i) =>
    `${i + 1}. ${clean(item.DES_PRODUTO)} (${Number(item.QTD_VENDIDA || 0)})`
  ).join('\n');
}

function loja(loja) {
  return `
🏬 Loja ${loja.COD_LOJA}
💰 ${brl.format(Number(loja.FATURAMENTO || 0))}
🧾 ${Number(loja.QTD_CUPONS || 0)} cupons
🎟️ ${brl.format(Number(loja.TICKET_MEDIO || 0))}

💳 Pagamentos:
${formatMeios(loja.MEIOS_PAGAMENTO)}

🔥 Top 5:
${formatTop(loja.TOP_5_PRODUTOS)}
`;
}

const mensagem = clean(`
📊 Resumo do Dia
📅 ${fmtDate(data.DATA)}

${loja(data.LOJA_1)}

${loja(data.LOJA_2)}

🧮 Total Geral: ${brl.format(Number(data.TOTAL_DIA.FATURAMENTO_TOTAL_DIA || 0))}
`);

return [{ json: { mensagem } }];

const data = $json;

const brl = new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL'
});

function clean(text) {
  return String(text || '').replace(/[<>`*_#\[\]\(\)]/g, '').trim();
}

function formatSetores(loja) {
  if (!loja.SETORES || loja.SETORES.length === 0) {
    return 'Sem dados';
  }

  return loja.SETORES.slice(0, 5).map((item, index) => {
    return `${index + 1}. ${clean(item.DES_SECAO)}
💰 Faturamento: ${brl.format(Number(item.FATURAMENTO || 0))}
💵 Lucro: ${brl.format(Number(item.LUCRO_BRUTO || 0))}
📈 Margem: ${Number(item.MARGEM_PERC || 0)}%`;
  }).join('\n\n');
}

const mensagem = [
  `Analise comercial do dia`,
  `Data: ${data.DATA}`,
  ``,
  `Loja 1`,
  formatSetores(data.LOJA_1),
  ``,
  `Loja 2`,
  formatSetores(data.LOJA_2)
].join('\n');

return [{ json: { mensagem } }];

const data = $json;

const brl = new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL'
});

function clean(text) {
  return String(text || '')
    .replace(/[<>`*_#\[\]\(\)]/g, '')
    .trim();
}

function formatLoja(loja) {
  if (!loja || !loja.TOP_10) {
    return 'Sem dados';
  }

  const top = loja.TOP_10.slice(0, 5).map((item, i) => {
    return `${i + 1}. ${clean(item.DES_PRODUTO)}
💰 ${brl.format(Number(item.FATURAMENTO || 0))}
📈 Margem: ${Number(item.MARGEM_PERC || 0)}%
🏷️ Curva ${item.CURVA_ABC}`;
  }).join('\n\n');

  const alertas = loja.TOP_10
    .filter(x => Number(x.MARGEM_PERC || 0) < 15)
    .slice(0, 3)
    .map(x => `• ${clean(x.DES_PRODUTO)} (${Number(x.MARGEM_PERC || 0)}%)`)
    .join('\n');

  return `🏬 Loja ${loja.COD_LOJA}
💰 Faturamento: ${brl.format(Number(loja.FATURAMENTO_TOTAL || 0))}
📦 Itens analisados: ${Number(loja.QTD_ITENS_ANALISADOS || 0)}

🔥 Top Produtos:
${top}

⚠️ Margens Baixas:
${alertas || 'Nenhum alerta relevante'}`;
}

const mensagem = `📊 RELATÓRIO CURVA ABC
📅 ${data.DATA || 'Ontem'}

${formatLoja(data.LOJA_1)}

${formatLoja(data.LOJA_2)}

🤖 Relatório automático`;

return [{ json: { mensagem } }];

const abc = $items("HTTP Request1")[0].json; 
const ia =
  $json.message?.content ||
  $json.content ||
  $json.output ||
  $json.text ||
  'Sem resumo gerado.';

const brl = new Intl.NumberFormat('pt-BR', {
  style: 'currency',
  currency: 'BRL'
});

function clean(text) {
  return String(text || '')
    .replace(/[<>]/g, '')
    .trim();
}

function escapeHtml(text) {
  return String(text || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function formatDate(value) {
  if (!value) return 'Sem data';
  return new Date(value).toLocaleDateString('pt-BR');
}

function badge(curva) {
  const map = {
    A: { bg: '#dcfce7', color: '#166534' },
    B: { bg: '#fef3c7', color: '#92400e' },
    C: { bg: '#fee2e2', color: '#991b1b' }
  };
  const c = map[curva] || { bg: '#e5e7eb', color: '#374151' };
  return `<span style="display:inline-block;padding:4px 10px;border-radius:999px;background:${c.bg};color:${c.color};font-size:12px;font-weight:700;">Curva ${curva}</span>`;
}

function topTable(loja) {
  const itens = loja?.TOP_10?.slice(0, 5) || [];
  if (!itens.length) {
    return `<div style="font-size:13px;color:#6b7280;">Sem dados</div>`;
  }

  const rows = itens.map((item, i) => `
    <tr>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;">${i + 1}</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;font-weight:600;">${escapeHtml(clean(item.DES_PRODUTO))}</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;">${escapeHtml(clean(item.DES_SECAO))}</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;text-align:right;">${Number(item.QTD_VENDIDA || 0).toFixed(2)}</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;text-align:right;">${brl.format(Number(item.FATURAMENTO || 0))}</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;text-align:right;">${Number(item.MARGEM_PERC || 0)}%</td>
      <td style="padding:10px;border-bottom:1px solid #e5e7eb;font-size:13px;">${badge(item.CURVA_ABC)}</td>
    </tr>
  `).join('');

  return `
    <table style="width:100%;border-collapse:collapse;background:#fff;border-radius:12px;overflow:hidden;">
      <thead>
        <tr style="background:#f9fafb;">
          <th style="padding:10px;text-align:left;font-size:12px;color:#6b7280;">#</th>
          <th style="padding:10px;text-align:left;font-size:12px;color:#6b7280;">Produto</th>
          <th style="padding:10px;text-align:left;font-size:12px;color:#6b7280;">Setor</th>
          <th style="padding:10px;text-align:right;font-size:12px;color:#6b7280;">Qtd</th>
          <th style="padding:10px;text-align:right;font-size:12px;color:#6b7280;">Fat.</th>
          <th style="padding:10px;text-align:right;font-size:12px;color:#6b7280;">Margem</th>
          <th style="padding:10px;text-align:left;font-size:12px;color:#6b7280;">ABC</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

function resumoCurva(loja) {
  const r = loja?.RESUMO_CURVA || {};
  const a = r.A || {};
  const b = r.B || {};
  const c = r.C || {};

  return `
    <table style="width:100%;border-collapse:collapse;">
      <tr>
        <td style="padding:8px 0;font-size:13px;">${badge('A')}</td>
        <td style="padding:8px 0;font-size:13px;">${a.QTD || 0} itens</td>
        <td style="padding:8px 0;font-size:13px;text-align:right;">${brl.format(Number(a.FATURAMENTO || 0))}</td>
      </tr>
      <tr>
        <td style="padding:8px 0;font-size:13px;">${badge('B')}</td>
        <td style="padding:8px 0;font-size:13px;">${b.QTD || 0} itens</td>
        <td style="padding:8px 0;font-size:13px;text-align:right;">${brl.format(Number(b.FATURAMENTO || 0))}</td>
      </tr>
      <tr>
        <td style="padding:8px 0;font-size:13px;">${badge('C')}</td>
        <td style="padding:8px 0;font-size:13px;">${c.QTD || 0} itens</td>
        <td style="padding:8px 0;font-size:13px;text-align:right;">${brl.format(Number(c.FATURAMENTO || 0))}</td>
      </tr>
    </table>
  `;
}

function alertList(loja) {
  const itens = loja?.TOP_10?.filter(x => Number(x.MARGEM_PERC || 0) < 15).slice(0, 3) || [];
  if (!itens.length) return `<li>Nenhum alerta crítico no top 10.</li>`;
  return itens.map(x => `<li>${escapeHtml(clean(x.DES_PRODUTO))} — margem ${Number(x.MARGEM_PERC || 0)}%</li>`).join('');
}

function lojaCard(loja, titulo) {
  return `
    <div style="background:#ffffff;border-radius:16px;padding:20px;box-shadow:0 2px 10px rgba(0,0,0,.06);margin-bottom:18px;">
      <div style="font-size:22px;font-weight:700;color:#111827;margin-bottom:14px;">${titulo}</div>

      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:18px;">
        <div style="background:#eff6ff;border-radius:12px;padding:14px;">
          <div style="font-size:12px;color:#6b7280;">Faturamento</div>
          <div style="font-size:20px;font-weight:700;color:#1d4ed8;">${brl.format(Number(loja.FATURAMENTO_TOTAL || 0))}</div>
        </div>
        <div style="background:#f0fdf4;border-radius:12px;padding:14px;">
          <div style="font-size:12px;color:#6b7280;">Itens analisados</div>
          <div style="font-size:20px;font-weight:700;color:#15803d;">${Number(loja.QTD_ITENS_ANALISADOS || 0)}</div>
        </div>
        <div style="background:#fff7ed;border-radius:12px;padding:14px;">
          <div style="font-size:12px;color:#6b7280;">Data</div>
          <div style="font-size:18px;font-weight:700;color:#c2410c;">${formatDate(loja.DATA)}</div>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:18px;">
        <div style="background:#f9fafb;border-radius:12px;padding:16px;">
          <div style="font-size:16px;font-weight:700;color:#111827;margin-bottom:10px;">Resumo da Curva</div>
          ${resumoCurva(loja)}
        </div>

        <div style="background:#f9fafb;border-radius:12px;padding:16px;">
          <div style="font-size:16px;font-weight:700;color:#111827;margin-bottom:10px;">Alertas rápidos</div>
          <ul style="margin:0;padding-left:18px;font-size:13px;line-height:1.7;color:#374151;">
            ${alertList(loja)}
          </ul>
        </div>
      </div>

      <div style="font-size:16px;font-weight:700;color:#111827;margin-bottom:10px;">Top 5 Produtos</div>
      ${topTable(loja)}
    </div>
  `;
}

const html = `
<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<title>Relatório ABC Diário</title>
</head>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:Arial,Helvetica,sans-serif;color:#111827;">
  <div style="max-width:1100px;margin:0 auto;padding:24px;">

    <div style="background:linear-gradient(135deg,#111827,#1f2937);color:#fff;border-radius:20px;padding:28px 32px;margin-bottom:20px;">
      <div style="font-size:14px;opacity:.8;">Relatório Comercial Automatizado</div>
      <div style="font-size:32px;font-weight:800;margin-top:8px;">📊 Curva ABC e Insights</div>
      <div style="font-size:15px;opacity:.9;margin-top:8px;">Referência: ${formatDate(abc.DATA)}</div>
    </div>

    <div style="background:#ffffff;border-radius:16px;padding:22px;box-shadow:0 2px 10px rgba(0,0,0,.06);margin-bottom:20px;">
      <div style="font-size:22px;font-weight:700;margin-bottom:12px;">📌 Resumo Executivo</div>
      <div style="font-size:15px;line-height:1.8;color:#374151;">
        ${escapeHtml(ia).replace(/\n/g, '<br>')}
      </div>
    </div>

    ${lojaCard(abc.LOJA_1, '🏬 Loja 1')}
    ${lojaCard(abc.LOJA_2, '🏬 Loja 2')}

    <div style="text-align:center;font-size:12px;color:#6b7280;padding:8px 0;">
      Relatório enviado automaticamente pelo pipeline de inteligência comercial.
    </div>
  </div>
</body>
</html>
`;

return [{ json: { html } }];
